//go:build ignore

// Command gen regenerates t2s_table.go from the shared source-of-truth
// sdks/data/han_t2s.tsv. Run via `go generate ./...` in this module.
//
// The TSV is the ONE source shared with the Python dict
// (sdks/python/loreweave_extraction/_han_simplified_table.py); regenerating from
// it guarantees the Go table never drifts from Python. TestT2SParityWithSoT also
// re-reads the TSV at test time so a stale generated file fails CI.
package main

import (
	"bufio"
	"fmt"
	"os"
	"sort"
	"strings"
)

const tsvPath = "../../data/han_t2s.tsv"
const outPath = "t2s_table.go"

func main() {
	f, err := os.Open(tsvPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "open %s: %v\n", tsvPath, err)
		os.Exit(1)
	}
	defer f.Close()

	type pair struct{ trad, simp rune }
	var pairs []pair
	sc := bufio.NewScanner(f)
	for sc.Scan() {
		line := sc.Text()
		if strings.HasPrefix(line, "#") || strings.TrimSpace(line) == "" {
			continue
		}
		cols := strings.Split(line, "\t")
		if len(cols) != 2 {
			fmt.Fprintf(os.Stderr, "bad line %q\n", line)
			os.Exit(1)
		}
		tr := []rune(cols[0])
		sr := []rune(cols[1])
		if len(tr) != 1 || len(sr) != 1 {
			fmt.Fprintf(os.Stderr, "each side must be one rune: %q\n", line)
			os.Exit(1)
		}
		pairs = append(pairs, pair{tr[0], sr[0]})
	}
	if err := sc.Err(); err != nil {
		fmt.Fprintf(os.Stderr, "scan: %v\n", err)
		os.Exit(1)
	}
	sort.Slice(pairs, func(i, j int) bool { return pairs[i].trad < pairs[j].trad })

	var b strings.Builder
	b.WriteString("// Code generated by `go generate`; DO NOT EDIT.\n")
	b.WriteString("// Source of truth: sdks/data/han_t2s.tsv (shared with the Python dict).\n\n")
	b.WriteString("package loreweave_extraction\n\n")
	b.WriteString("// T2S maps each traditional Han rune to its simplified form. Frozen, curated\n")
	b.WriteString("// subset — see the TSV header. Identical to the Python loreweave_extraction T2S.\n")
	b.WriteString("var T2S = map[rune]rune{\n")
	for _, p := range pairs {
		b.WriteString(fmt.Sprintf("\t0x%04X: 0x%04X, // %c -> %c\n", p.trad, p.simp, p.trad, p.simp))
	}
	b.WriteString("}\n")

	if err := os.WriteFile(outPath, []byte(b.String()), 0o644); err != nil {
		fmt.Fprintf(os.Stderr, "write %s: %v\n", outPath, err)
		os.Exit(1)
	}
	fmt.Printf("wrote %s: %d pairs\n", outPath, len(pairs))
}
